// ── Computed Adjacency Maps ─────────────────────────────────────────

/** Land space adjacency: { spaceName: { connections: [...], passes: [...] } } */
export const LAND_ADJACENCY = (() => {
  const adj = {};
  for (const sp of LAND_SPACES) {
    adj[sp.name] = { connections: [], passes: [] };
  }
  for (const edge of LAND_EDGES) {
    const list = edge.type === 'pass' ? 'passes' : 'connections';
    if (adj[edge.a]) adj[edge.a][list].push(edge.b);
    if (adj[edge.b]) adj[edge.b][list].push(edge.a);
  }
  return adj;
})();

/** Sea zone adjacency: { seaZoneName: [...neighborSeaZones] } */
export const SEA_ADJACENCY = (() => {
  const adj = {};
  for (const sz of SEA_ZONES) adj[sz] = [];
  for (const edge of SEA_EDGES) {
    if (adj[edge.a]) adj[edge.a].push(edge.b);
    if (adj[edge.b]) adj[edge.b].push(edge.a);
  }
  return adj;
})();

/** Ports by sea zone: { seaZoneName: [...portSpaceNames] } */
export const PORTS_BY_SEA_ZONE = (() => {
  const map = {};
  for (const sz of SEA_ZONES) map[sz] = [];
  for (const sp of LAND_SPACES) {
    if (sp.isPort) {
      for (const sz of sp.connectedSeaZones) {
        if (map[sz]) map[sz].push(sp.name);
      }
    }
  }
  return map;
})();

/** Lookup land space by name */
export const SPACE_BY_NAME = Object.fromEntries(
  LAND_SPACES.map(sp => [sp.name, sp])
);

